#!/usr/bin/perl

use strict;
use warnings;
use CGI;
use CGI::Carp qw(fatalsToBrowser);

my $q = CGI->new;

# Configuration
my $log_dir = "/var/log"; # Directory where log files are stored
my $max_lines = 1000;     # Maximum number of lines to display
my @allowed_log_files = qw(
    syslog
    auth.log
    kern.log
    dpkg.log
    user.log
    daemon.log
    messages
    debug
    mail.log
    apache2/access.log
    apache2/error.log
    nginx/access.log
    nginx/error.log
); # Whitelist of allowed log files (relative to $log_dir)

print $q->header;
print $q->start_html("Log File Viewer");

my $filename = $q->param('logfile');

if (!$filename) {
    print $q->h1("Log File Viewer");
    print $q->p("Please select a log file to view:");
    print $q->ul(
        map {
            my $display_name = $_;
            $display_name =~ s/\// /g; # Replace slashes with spaces for display
            $q->li( $q->a({href => $q->url(-query => {logfile => $_})}, $display_name) )
        } @allowed_log_files
    );
    print $q->end_html;
    exit;
}

# Sanitize and validate filename
my $is_allowed = 0;
foreach my $allowed_file (@allowed_log_files) {
    if ($filename eq $allowed_file) {
        $is_allowed = 1;
        last;
    }
}

if (!$is_allowed) {
    print $q->h1("Error");
    print $q->p("Invalid or disallowed log file specified: ", $q->em($q->escapeHTML($filename)));
    print $q->p("Please select from the allowed list.");
    print $q->end_html;
    exit;
}

# Construct the full path
my $full_path = "$log_dir/$filename";

# Ensure the path doesn't escape the log directory (double-check, though whitelist should prevent)
if ($full_path !~ m{^\Q$log_dir\E/[a-zA-Z0-9_./-]+$} || $full_path =~ m{/\.\./}) {
    print $q->h1("Error");
    print $q->p("Security warning: Attempt to access an invalid path.");
    print $q->end_html;
    exit;
}

print $q->h1("Viewing Log File: ", $q->escapeHTML($filename));
print $q->p("Displaying up to $max_lines lines.");
print $q->hr;

print $q->pre({-style => 'white-space: pre-wrap; word-wrap: break-word; background-color: #f0f0f0; padding: 10px; border: 1px solid #ccc;'});

my $line_count = 0;
if (open(my $fh, "<", $full_path)) {
    while (my $line = <$fh>) {
        print $q->escapeHTML($line);
        $line_count++;
        last if $line_count >= $max_lines;
    }
    close($fh);
} else {
    print $q->p("Error opening log file: ", $q->escapeHTML($full_path), " - $!");
}

print $q->pre_end;
print $q->hr;
print $q->p($q->a({href => $q->url(-query => {})}, "Back to Log File List"));
print $q->end_html;